import json
import sys

def load_exchange_rates():
    try:
        with open('exchange_rates.json', 'r') as file:
            return json.load(file)
    except FileNotFoundError:
        print("Exchange rates configuration file not found.")
        sys.exit(1)

def convert_currency(amount, source_currency, target_currency, exchange_rates):
    if source_currency not in exchange_rates or target_currency not in exchange_rates[source_currency]:
        print("Conversion rate not available.")
        return None
    return amount * exchange_rates[source_currency][target_currency]

def main():
    exchange_rates = load_exchange_rates()

    amount = float(input("Enter amount: "))
    source_currency = input("Enter source currency: ").upper()
    target_currency = input("Enter target currency: ").upper()

    converted_amount = convert_currency(amount, source_currency, target_currency, exchange_rates)
    if converted_amount is not None:
        print(f"{amount} {source_currency} is {converted_amount:.2f} {target_currency}")

if __name__ == "__main__":
